```class Solution {
public:
    string maximumBinaryString(string binary) {
        int n = binary.size();
        int cnt = 0;
        for (int i = 0; i < n; i++) {
            if (binary[i] == '0') {
                cnt = i;
                break;
            }
        }
        for (int i = cnt; i < n; i++) {
            binary[i] = '1';
        }
        return binary;
    }
};
